#!/usr/bin/env python3
# -*- coding: utf-8 -*-

import sys


def read_data():
    a1, b1, a2, b2, L, R = map(int, sys.stdin.readline().split())
    return a1, b1, a2, b2, L, R


def solve(a1, b1, a2, b2, L, R):
    ans = 0
    for x in range(L, R + 1):
        if (x - b1) % a1 == 0 and (x - b2) % a2 == 0:
            ans += 1
    return ans


def main():
    a1, b1, a2, b2, L, R = read_data()
    print(solve(a1, b1, a2, b2, L, R))


if __name__ == '__main__':
    main()
